import os
import boto3
from botocore.exceptions import NoCredentialsError, PartialCredentialsError

def fetch_latest_model(model_path_env_var):
    # Retrieve the model path from environment variable
    model_path = os.getenv(model_path_env_var)
    if not model_path:
        raise ValueError("Model path environment variable is not set.")

    # Extract bucket name and key from the model path
    if 's3://' in model_path:
        s3_url_parts = model_path.replace('s3://', '').split('/')
        bucket_name = s3_url_parts[0]
        object_key = '/'.join(s3_url_parts[1:])
    else:
        raise ValueError("Unsupported storage service. Only S3 is supported.")

    # Initialize the S3 client
    s3_client = boto3.client('s3')

    try:
        # List objects in the bucket with the same prefix to find the latest version
        response = s3_client.list_objects_v2(Bucket=bucket_name, Prefix=object_key)
        if 'Contents' not in response or len(response['Contents']) == 0:
            raise FileNotFoundError("No model found at the specified path.")

        # Find the latest model version based on the last modified date
        latest_model = max(response['Contents'], key=lambda x: x['LastModified'])
        latest_model_key = latest_model['Key']

        # Download the latest model to a local file
        local_model_path = os.path.join('/tmp', os.path.basename(latest_model_key))
        s3_client.download_file(bucket_name, latest_model_key, local_model_path)

        return local_model_path

    except (NoCredentialsError, PartialCredentialsError) as e:
        raise RuntimeError("AWS credentials not found or incomplete.") from e
    except Exception as e:
        raise RuntimeError(f"An error occurred while fetching the model: {e}") from e

# Example usage
if __name__ == "__main__":
    MODEL_PATH_ENV_VAR = 'MODEL_PATH'
    try:
        local_model_path = fetch_latest_model(MODEL_PATH_ENV_VAR)
        print(f"Latest model downloaded to: {local_model_path}")
        # Proceed with loading the model for inference
    except Exception as e:
        print(f"Error: {e}")